namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _sut = new NotificationService();
        // Drain any pre-existing notifications from the static queue
        while (_sut.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        // Act
        _sut.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_EnqueuesNotificationWithIdInMessage()
    {
        // Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("ID: 42"), $"Message was: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_MessageContainsDisplayName()
    {
        // Act
        _sut.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("John Smith"), $"Message was: {notification.Message}");
    }

    [TestMethod]
    public void SendNotification_WithNullUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE, null);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "42", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_CreateOperation_MessageContainsCreated()
    {
        // Act
        _sut.SendNotification("Course", "100", "Chemistry", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
    }

    [TestMethod]
    public void SendNotification_UpdateOperation_MessageContainsUpdated()
    {
        // Act
        _sut.SendNotification("Course", "100", "Chemistry", EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_DeleteOperation_MessageContainsDeleted()
    {
