        _sut.MarkAsRead(0);
        _sut.MarkAsRead(-1);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        service.Dispose();
        // Should not throw even after disposal
    }

