using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndex()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var list = new PaginatedList<string>(items, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
    }

    [TestMethod]
    public void Constructor_CalculatesTotalPages_ExactDivision()
    {
        // Arrange - 10 items, page size 5 => 2 pages
        var items = new List<string> { "a", "b", "c", "d", "e" };

        // Act
        var list = new PaginatedList<string>(items, 10, 1, 5);

        // Assert
