using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class HomeControllerTests
{
    private SchoolContext _context = null!;
    private HomeController _controller = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new HomeController(_context);
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Contact_ReturnsViewResult()
    {
        // Act
        var result = _controller.Contact();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Contact_SetsViewBagMessage()
    {
        // Act
        var result = _controller.Contact() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Your contact page.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void Error_ReturnsViewResult()
    {
        // Act
        var result = _controller.Error();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_ReturnsViewResult()
    {
        // Act
        var result = _controller.Unauthorized();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void Unauthorized_SetsViewBagMessage()
    {
        // Act
        _controller.Unauthorized();

        // Assert
        Assert.AreEqual("You don't have permission to access this resource.", _controller.ViewBag.Message);
    }

    [TestMethod]
    public void About_WithNoStudents_ReturnsEmptyList()
    {
        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(0, model.Count);
    }

    [TestMethod]
    public void About_WithStudents_ReturnsGroupedEnrollmentDates()
    {
        // Arrange
        var date1 = DateTime.Parse("2010-09-01");
        var date2 = DateTime.Parse("2012-09-01");
        _context.Students.AddRange(
            new Student { FirstMidName = "A", LastName = "A", EnrollmentDate = date1 },
            new Student { FirstMidName = "B", LastName = "B", EnrollmentDate = date1 },
            new Student { FirstMidName = "C", LastName = "C", EnrollmentDate = date2 }
        );
        _context.SaveChanges();

        // Act
        var result = _controller.About() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as List<ContosoUniversity.Models.SchoolViewModels.EnrollmentDateGroup>;
        Assert.IsNotNull(model);
        Assert.AreEqual(2, model.Count);

        var group1 = model.Single(g => g.EnrollmentDate == date1);
        Assert.AreEqual(2, group1.StudentCount);

        var group2 = model.Single(g => g.EnrollmentDate == date2);
        Assert.AreEqual(1, group2.StudentCount);
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using System.Net;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private SchoolContext _context = null!;
    private StudentsController _controller = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new StudentsController(_context);

        // Set up TempData (needed for DeleteConfirmed error path)
        var httpContext = new DefaultHttpContext();
        var tempData = new TempDataDictionary(httpContext, Mock.Of<ITempDataProvider>());
        _controller.TempData = tempData;
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    #region Index Tests

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithPaginatedList()
    {
        // Arrange
        TestHelpers.SeedTestData(_context);

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count > 0);
    }

    [TestMethod]
    public void Index_WithSearchString_FiltersStudents()
    {
        // Arrange
        TestHelpers.SeedTestData(_context);

        // Act
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Arrange
        TestHelpers.SeedTestData(_context);

        // Act
        var result = _controller.Index("", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count >= 2);
        // Default sort is by last name ascending
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Arrange
        TestHelpers.SeedTestData(_context);

        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count >= 2);
        // name_desc sorts by last name descending
        Assert.IsTrue(string.Compare(model[0].LastName, model[1].LastName) > 0);
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        TestHelpers.SeedTestData(_context);

        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count >= 2);
        Assert.IsTrue(model[0].EnrollmentDate <= model[1].EnrollmentDate);
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Arrange
        TestHelpers.SeedTestData(_context);

        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count >= 2);
        Assert.IsTrue(model[0].EnrollmentDate >= model[1].EnrollmentDate);
