using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class NotificationsControllerTests
{
    private SchoolContext _context = null!;
    private NotificationsController _controller = null!;
    private NotificationService _drainService = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = new NotificationsController(_context);
        // Drain any pre-existing notifications from the static queue
        _drainService = new NotificationService();
        while (_drainService.ReceiveNotification() != null) { }
    }

    [TestCleanup]
    public void TestCleanup()
    {
        // Drain again to clean up
        while (_drainService.ReceiveNotification() != null) { }
        _drainService.Dispose();
        _controller.Dispose();
        _context.Dispose();
    }

    [TestMethod]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index();

        // Assert
        Assert.IsInstanceOfType<ViewResult>(result);
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);

        // Verify the result value has success=true and count=0
        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - enqueue notifications via the service
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
        service.SendNotification("Course", "100", "Test Course", EntityOperation.UPDATE);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(2, countProp.GetValue(value));

        service.Dispose();
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - enqueue more than 10 notifications
        var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var value = result.Value;
        Assert.IsNotNull(value);

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(10, countProp.GetValue(value));

        service.Dispose();
    }

    [TestMethod]
    public void MarkAsRead_ReturnsSuccessJson()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.IsNotNull(result);
        Assert.IsInstanceOfType<JsonResult>(result);

        var value = result.Value;
        Assert.IsNotNull(value);

        var successProp = value.GetType().GetProperty("success");
        Assert.IsNotNull(successProp);
        Assert.AreEqual(true, successProp.GetValue(value));
    }

    [TestMethod]
    public void GetNotifications_DequeuesFromQueue()
    {
        // Arrange
        var service = new NotificationService();
        service.SendNotification("Student", "1", EntityOperation.CREATE);

        // Act - first call dequeues
        _controller.GetNotifications();

        // Second call should be empty
        var result = _controller.GetNotifications();
        var value = result.Value;
        Assert.IsNotNull(value);

        var countProp = value.GetType().GetProperty("count");
        Assert.IsNotNull(countProp);
        Assert.AreEqual(0, countProp.GetValue(value));

        service.Dispose();
    }
}

