using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    private SchoolContext _context = null!;

    [TestInitialize]
    public void TestInitialize()
    {
        _context = TestHelpers.CreateInMemoryContext();
    }

    [TestCleanup]
    public void TestCleanup()
    {
        _context.Dispose();
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(8, _context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(5, _context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(4, _context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(7, _context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(3, _context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(8, _context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        Assert.AreEqual(11, _context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        // Arrange - seed once
        DbInitializer.Initialize(_context);
        var studentCountAfterFirst = _context.Students.Count();
        var courseCountAfterFirst = _context.Courses.Count();

        // Act - seed again
        DbInitializer.Initialize(_context);

        // Assert - counts should not change
        Assert.AreEqual(studentCountAfterFirst, _context.Students.Count());
        Assert.AreEqual(courseCountAfterFirst, _context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_SeedsCorrectStudentNames()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert - verify specific known seed data
        var carson = _context.Students.FirstOrDefault(s => s.LastName == "Alexander");
        Assert.IsNotNull(carson);
        Assert.AreEqual("Carson", carson.FirstMidName);

        var meredith = _context.Students.FirstOrDefault(s => s.LastName == "Alonso");
        Assert.IsNotNull(meredith);
        Assert.AreEqual("Meredith", meredith.FirstMidName);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectCourseData()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var chemistry = _context.Courses.FirstOrDefault(c => c.Title == "Chemistry");
        Assert.IsNotNull(chemistry);
        Assert.AreEqual(1050, chemistry.CourseID);
        Assert.AreEqual(3, chemistry.Credits);

        var calculus = _context.Courses.FirstOrDefault(c => c.Title == "Calculus");
        Assert.IsNotNull(calculus);
        Assert.AreEqual(1045, calculus.CourseID);
        Assert.AreEqual(4, calculus.Credits);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectDepartmentBudgets()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var english = _context.Departments.FirstOrDefault(d => d.Name == "English");
        Assert.IsNotNull(english);
        Assert.AreEqual(350000m, english.Budget);

        var math = _context.Departments.FirstOrDefault(d => d.Name == "Mathematics");
        Assert.IsNotNull(math);
        Assert.AreEqual(100000m, math.Budget);
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert - verify some enrollments have grades and some don't
        var enrollmentsWithGrades = _context.Enrollments.Where(e => e.Grade != null).Count();
        var enrollmentsWithoutGrades = _context.Enrollments.Where(e => e.Grade == null).Count();

        Assert.IsTrue(enrollmentsWithGrades > 0, "Should have enrollments with grades");
        Assert.IsTrue(enrollmentsWithoutGrades > 0, "Should have enrollments without grades");
    }

    [TestMethod]
    public void Initialize_AssignsDepartmentAdministrators()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert - all departments should have an InstructorID set
        var departments = _context.Departments.ToList();
        foreach (var dept in departments)
        {
            Assert.IsNotNull(dept.InstructorID, $"Department '{dept.Name}' should have an administrator");
        }
    }

    [TestMethod]
    public void Initialize_SeedsOfficeLocations()
    {
        // Act
        DbInitializer.Initialize(_context);

        // Assert
        var offices = _context.OfficeAssignments.ToList();
        Assert.IsTrue(offices.Any(o => o.Location == "Smith 17"));
        Assert.IsTrue(offices.Any(o => o.Location == "Gowan 27"));
        Assert.IsTrue(offices.Any(o => o.Location == "Thompson 304"));
    }
}

